mapper.select:
SELECT q.id AS questionId, q.title AS title, q.writer_id AS writerId, NULL AS writerNickname, q.status AS status, q.visibility AS visibility, q.answer_count AS answerCount, q.like_count AS likeCount, q.view_count AS viewCount, q.created_at AS createdAt FROM questions q WHERE q.visibility = 'PUBLIC' AND q.delflag = 'N'
AND ( LOWER(q.title) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(q.content) LIKE CONCAT('%', LOWER(#{keyword}), '%') )
AND q.status = #{status}
AND EXISTS ( SELECT 1 FROM question_tech_stacks qts WHERE qts.question_id = q.id AND qts.tech_stack_id IN
#{techStackId}
)
ORDER BY q.like_count DESC, q.created_at DESC
ORDER BY q.created_at DESC
